// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Webpack
// plugin that tells the Electron app where to look for the Webpack-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_WEBPACK_ENTRY: string;
declare const MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY: string;

// Handle creating/removing shortcuts on Windows when installing/uninstalling.
if (require('electron-squirrel-startup')) {
	app.quit();
}

let mainWindow: BrowserWindow;
let fileWatcher: chokidar.FSWatcher | null = null;
let fileWatcherPath: string | null = null;
let fileWatcherLastEvent: Date | null = null;
let fileWatcherError: string | null = null;

const createWindow = () => {
	console.log('[MAIN] Creating window...');
	console.log('[MAIN] Preload path:', MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY);
	console.log('[MAIN] Renderer path:', MAIN_WINDOW_WEBPACK_ENTRY);
	console.log(
		'[MAIN] Preload file exists:',
		fs.existsSync(MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY)
	);

	// Additional debugging
	try {
		const stats = fs.statSync(MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY);
		console.log('[MAIN] Preload file size:', stats.size, 'bytes');
	} catch (error) {
		console.error('[MAIN] Error checking preload file:', error);
	}

	mainWindow = new BrowserWindow({
		height: 800,
		width: 1200,
		minHeight: 600,
		minWidth: 1000,
		frame: false, // custom chrome
		transparent: false, // fully opaque window
		hasShadow: true,
		backgroundColor: '#0b1420',
		titleBarStyle: 'hidden',
		roundedCorners: true,
		webPreferences: {
			preload: MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY,
			nodeIntegration: false,
			contextIsolation: true,
			webSecurity: true, // Re-enabled since IPC is working
		},
		acceptFirstMouse: true,
	});

	// Ensure native traffic lights are hidden when using custom chrome
	try {
		// macOS only
		(mainWindow as any).setWindowButtonVisibility?.(false);
	} catch (e) {
		// no-op
	}

	// Ensure no vibrancy is applied; we want an opaque window

	// Listen for console messages from the renderer process
	mainWindow.webContents.on(
		'console-message',
		(event, level, message, line, sourceId) => {
			const levelMap: Record<number, string> = {
				0: 'INFO',
				1: 'WARN',
				2: 'ERROR',
				3: 'DEBUG',
			};
			const logLevel = levelMap[level] || 'LOG';
			console.log(`[RENDERER-${logLevel}] ${message}`);
		}
	);

	// Listen for when the renderer is ready
	mainWindow.webContents.once('did-finish-load', () => {
		console.log('[MAIN] Renderer finished loading');
		// Check if preload worked by evaluating window.electronAPI
		mainWindow.webContents
			.executeJavaScript('!!window.electronAPI')
			.then((hasAPI) => {
				console.log('[MAIN] electronAPI available in renderer:', hasAPI);
			})
			.catch((err) => {
				console.error('[MAIN] Failed to check electronAPI:', err);
			});
	});

	// Listen for preload script errors
	mainWindow.webContents.on('preload-error', (event, preloadPath, error) => {
		console.error('[MAIN] Preload script error:', preloadPath, error);
	});

	// Listen for when DOM is ready
	mainWindow.webContents.once('dom-ready', () => {
		console.log('[MAIN] DOM ready');
	});

    mainWindow.loadURL(MAIN_WINDOW_WEBPACK_ENTRY);

    if (!app.isPackaged) {
        mainWindow.webContents.openDevTools();
    }
};

const getAgentStatusSnapshot = (): AgentStatus[] => {
	const watcherActive = Boolean(fileWatcher);
	const watcherStatus = (() => {
		if (fileWatcherError) {
			return `Error: ${fileWatcherError}`;
		}
		if (watcherActive && fileWatcherPath) {
			return `Watching ${fileWatcherPath}`;
		}
		return 'Idle';
	})();

	const statuses: AgentStatus[] = [
		{
			name: 'file-watcher',
			active: watcherActive,
			lastRun: fileWatcherLastEvent ?? undefined,
			status: watcherStatus,
			error: fileWatcherError ?? undefined,
		},
		{
			name: 'auto-save',
			active: false,
			status: 'Manual save only',
		},
	];

	return statuses;
};

const broadcastAgentStatuses = () => {
	if (!mainWindow || mainWindow.isDestroyed()) {
		return;
	}
	mainWindow.webContents.send(
		CHANNELS.onAgentStatusChange,
		getAgentStatusSnapshot()
	);
};

const startFileWatcher = (targetPath: string | null) => {
	if (fileWatcher) {
		fileWatcher.close();
		fileWatcher = null;
	}

	if (!targetPath) {
		fileWatcherPath = null;
		fileWatcherLastEvent = null;
		fileWatcherError = null;
		broadcastAgentStatuses();
		return;
	}

	fileWatcher = chokidar.watch(targetPath, {
		persistent: true,
		ignoreInitial: true,
	});

	fileWatcherPath = targetPath;
	fileWatcherLastEvent = null;
	fileWatcherError = null;
	broadcastAgentStatuses();

	fileWatcher.on('change', (changedPath: string) => {
		fileWatcherLastEvent = new Date();
		if (mainWindow && !mainWindow.isDestroyed()) {
			mainWindow.webContents.send(CHANNELS.onFileChanged, changedPath);
		}
		broadcastAgentStatuses();
	});

	fileWatcher.on('error', (error) => {
		console.error(`File watcher error: ${error}`);
		fileWatcherError = error instanceof Error ? error.message : String(error);
		broadcastAgentStatuses();
	});

	fileWatcher.on('ready', () => {
		broadcastAgentStatuses();
	});
};

app.on('ready', () => {
	createWindow();
});

app.on('window-all-closed', () => {
	if (process.platform !== 'darwin') {
		app.quit();
	}
});

app.on('activate', () => {
	if (BrowserWindow.getAllWindows().length === 0) {
		createWindow();
	}
});

