// Global error handlers
process.on('uncaughtException', (error) => {
	console.error('Uncaught Exception:', error);
	// Don't exit for destroyed object errors during shutdown
	if (error.message && error.message.includes('Object has been destroyed')) {
		console.log('Ignoring "Object has been destroyed" error during shutdown');
		return;
	}
	// For other critical errors, exit gracefully
	process.exit(1);
});

process.on('unhandledRejection', (reason, promise) => {
	console.error('Unhandled Rejection at:', promise, 'reason:', reason);
	// Don't crash for destroyed object errors
	if (
		reason &&
		typeof reason === 'object' &&
		'message' in reason &&
		typeof (reason as any).message === 'string' &&
		(reason as any).message.includes('Object has been destroyed')
	) {
		console.log(
			'Ignoring "Object has been destroyed" rejection during shutdown'
		);
		return;
	}
});

ipcMain.handle(CHANNELS.checkIsDirectory, async (event, filePath: string) => {
	try {
		const stats = await fs.promises.stat(filePath);
		return stats.isDirectory();
	} catch (error) {
		return false;
	}
});

ipcMain.handle(CHANNELS.createTestFiles, async () => {
	const baseDir = await fs.promises.mkdtemp(
		path.join(os.tmpdir(), 'metadata-editor-')
	);

	const templates: Array<{
		filename: string;
		metadata: Partial<Wavedata>;
	}> = [
		{
			filename: 'SHOW1_Dialogue_Sc01A_01.wav',
			metadata: {
				show: 'SHOW1',
				category: 'Dialogue',
				subcategory: '01',
				scene: '01A',
				take: '01',
				slate: 'A',
				ixmlNote: 'First take',
				ixmlCircled: 'true',
				ixmlWildtrack: 'false',
			},
		},
		{
			filename: 'SHOW1_Music_Sc02_02.wav',
			metadata: {
				show: 'SHOW1',
				category: 'Music',
				subcategory: '02',
				scene: '02',
				take: '02',
				slate: '',
				ixmlNote: 'Background score',
				ixmlCircled: 'false',
				ixmlWildtrack: 'false',
			},
		},
		{
			filename: 'SHOW2_SFX_Sc10B_03.wav',
			metadata: {
				show: 'SHOW2',
				category: 'SFX',
				subcategory: '10',
				scene: '10B',
				take: '03',
				slate: 'B',
				ixmlNote: 'Explosion effect',
				ixmlCircled: 'false',
				ixmlWildtrack: 'true',
			},
		},
	];

	const createdFiles: string[] = [];
	const errors: Array<{ filePath: string; error: string }> = [];

	for (const template of templates) {
		const filePath = path.join(baseDir, template.filename);
		try {
			const wav = new WaveFile();
			const sampleRate = 48000;
			const durationSeconds = 2;
			const totalSamples = sampleRate * durationSeconds;
			const silence = new Array(totalSamples).fill(0);

			wav.fromScratch(1, sampleRate, '16', silence);
			const buffer = wav.toBuffer();
			await fs.promises.writeFile(filePath, buffer);

			const existing = await metadataService.readMetadata(filePath);
			const updated: Wavedata = {
				...existing,
				...template.metadata,
			};

			await metadataService.writeMetadata(filePath, updated);
			createdFiles.push(filePath);
		} catch (error) {
			const message = error instanceof Error ? error.message : String(error);
			errors.push({ filePath, error: message });
			console.error(`Failed to create test file ${filePath}:`, message);
		}
	}

	return {
		success: errors.length === 0,
		directory: baseDir,
		files: createdFiles,
		errors,
	};
});

ipcMain.handle(CHANNELS.batchUpdateMetadata, async (event, updates) => {
	if (!Array.isArray(updates) || updates.length === 0) {
		return;
	}

	type UpdateEntry = {
		field: keyof Wavedata;
		value: unknown;
	};

	const groupedUpdates = updates.reduce((acc, update) => {
		if (!update || typeof update !== 'object') {
			return acc;
		}

		const { filePath, field, value } = update as {
			filePath: string;
			field: keyof Wavedata;
			value: unknown;
		};

		if (!filePath || typeof filePath !== 'string') {
			return acc;
		}

		const entry = acc.get(filePath) ?? [];
		entry.push({ field, value } as UpdateEntry);
		acc.set(filePath, entry);
		return acc;
	}, new Map<string, UpdateEntry[]>());

	const errors: string[] = [];

	for (const [filePath, fileUpdates] of groupedUpdates.entries()) {
		try {
			const metadata = await metadataService.readMetadata(filePath);
			const updatedMetadata: Wavedata = {
				...metadata,
				bwf: metadata.bwf ? { ...metadata.bwf } : undefined,
				iXML: metadata.iXML
					? JSON.parse(JSON.stringify(metadata.iXML))
					: undefined,
			};

			for (const { field, value } of fileUpdates) {
				if (!field) continue;

				switch (field) {
					case 'ixmlCircled':
					case 'ixmlWildtrack':
						(updatedMetadata as any)[field] =
							value === 'true' || value === true ? 'true' : 'false';
						break;
					case 'bwf':
					case 'iXML':
					case 'fileInfo':
					case 'duration':
					case 'fileSize':
						// Skip unsupported batch updates for complex fields
						console.warn(
							`Skipping batch update for unsupported field "${field}" on ${filePath}`
						);
						break;
					default:
						(updatedMetadata as any)[field] = value;
						break;
				}
			}

			await metadataService.writeMetadata(filePath, updatedMetadata);
		} catch (error) {
			const message = error instanceof Error ? error.message : String(error);
			errors.push(`${filePath}: ${message}`);
			console.error(`[MAIN] Failed batch update for ${filePath}:`, message);
		}
	}

	if (errors.length > 0) {
		throw new Error(
			`Failed to update metadata for ${errors.length} file(s): ${errors.join(
				'; '
			)}`
		);
	}
});

ipcMain.handle(
	CHANNELS.batchExtractMetadata,
	async (event, filePaths: string[]) => {
		console.log('[IPC] Received batchExtractMetadata request for:', filePaths);
		const results = filePaths.map((filePath) => {
			const filename = path.basename(filePath);
			const parsedData = filenameParser.parse(filename);
			if (parsedData) {
				return {
					...parsedData,
					filePath,
				};
			}
			return null;
		});
		const finalResults = results.filter((r) => r !== null);
		console.log('[IPC] Sending back extracted data:', finalResults);
		return finalResults;
	}
);

ipcMain.handle(CHANNELS.getAgentStatuses, async () => {
	return getAgentStatusSnapshot();
});

ipcMain.handle(CHANNELS.toggleAgent, async (event, name, active) => {
	if (name === 'file-watcher') {
		if (!active) {
			startFileWatcher(null);
			return;
		}

		if (fileWatcherPath) {
			startFileWatcher(fileWatcherPath);
			return;
		}

		throw new Error('No file path available to start watcher');
	}

	throw new Error(`Unknown agent: ${name}`);
});

ipcMain.handle(CHANNELS.triggerAgent, async (event, name) => {
	if (name === 'file-watcher') {
		if (fileWatcherPath) {
			startFileWatcher(fileWatcherPath);
			return;
		}
		throw new Error('No file path available to trigger watcher');
	}

	throw new Error(`Unknown agent: ${name}`);
});

